import { Component, OnDestroy, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormArray, FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Subject, startWith, takeUntil } from 'rxjs';

type ProductType = 'carre' | 'rectangle' | 'porte' | 'box';

interface AccessoryFormValue {
  designation?: string | null;
  quantite?: number | null;
  prixUnitaire?: number | null;
}

interface EstimationResult {
  baseMetres: number;
  consommationTotaleMetres: number;
  longueurAcheteeTotale: number;
  nbBarres: number;
  chuteTotale: number;
  coutBarres: number;
  surfaceVerre: number;
  coutVerre: number;
  coutAccessoires: number;
  coutTotal: number;
}

@Component({
  selector: 'app-estimation',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './estimation.component.html',
  styleUrls: ['./estimation.component.css']
})
export class EstimationComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  form = this.fb.group({
    barre: this.fb.group({
      longueurBarre: [6, [Validators.required, Validators.min(0.1)]],
      prixBarre: [0, [Validators.min(0)]]
    }),
    produit: this.fb.group({
      type: ['rectangle' as ProductType],
      cote: [0],
      largeur: [0],
      hauteur: [0],
      profondeur: [0],
      cadreRenfort: [false]
    }),
    options: this.fb.group({
      margeChute: [0],
      pertesCoupeCm: [0.2]
    }),
    verre: this.fb.group({
      activerVerre: [false],
      prixVerreM2: [0]
    }),
    accessoires: this.fb.array([])
  });

  result: EstimationResult = {
    baseMetres: 0,
    consommationTotaleMetres: 0,
    longueurAcheteeTotale: 0,
    nbBarres: 0,
    chuteTotale: 0,
    coutBarres: 0,
    surfaceVerre: 0,
    coutVerre: 0,
    coutAccessoires: 0,
    coutTotal: 0
  };

  constructor(private fb: FormBuilder) {}

  get accessoires(): FormArray {
    return this.form.get('accessoires') as FormArray;
  }

  get productType(): ProductType {
    return (this.form.get('produit.type')?.value as ProductType) ?? 'rectangle';
  }

  ngOnInit(): void {
    this.form.valueChanges
      .pipe(startWith(this.form.getRawValue()), takeUntil(this.destroy$))
      .subscribe(() => this.compute());
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  addAccessory(): void {
    this.accessoires.push(this.createAccessory());
  }

  removeAccessory(index: number): void {
    this.accessoires.removeAt(index);
  }

  reset(): void {
    this.form.reset({
      barre: {
        longueurBarre: 6,
        prixBarre: 0
      },
      produit: {
        type: 'rectangle',
        cote: 0,
        largeur: 0,
        hauteur: 0,
        profondeur: 0,
        cadreRenfort: false
      },
      options: {
        margeChute: 0,
        pertesCoupeCm: 0.2
      },
      verre: {
        activerVerre: false,
        prixVerreM2: 0
      },
      accessoires: []
    });

    this.accessoires.clear();
    this.compute();
  }

  print(): void {
    window.print();
  }

  compute(): void {
    const raw = this.form.getRawValue();

    const longueurBarre = Math.max(0, this.toNumber(raw.barre?.longueurBarre));
    const prixBarre = Math.max(0, this.toNumber(raw.barre?.prixBarre));

    const type = (raw.produit?.type as ProductType) ?? 'rectangle';
    const cote = Math.max(0, this.toNumber(raw.produit?.cote));
    const largeur = Math.max(0, this.toNumber(raw.produit?.largeur));
    const hauteur = Math.max(0, this.toNumber(raw.produit?.hauteur));
    const profondeur = Math.max(0, this.toNumber(raw.produit?.profondeur));
    const cadreRenfort = !!raw.produit?.cadreRenfort;

    let baseMetres = 0;
    let surfaceVerre = 0;
    let cuts = 0;

    switch (type) {
      case 'carre':
        baseMetres = 4 * cote;
        surfaceVerre = cote * cote;
        cuts = 4;
        break;
      case 'rectangle':
        baseMetres = 2 * (largeur + hauteur);
        surfaceVerre = largeur * hauteur;
        cuts = 4;
        break;
      case 'porte':
        // Porte simple: perimetre + renfort optionnel (une traverse)
        baseMetres = 2 * (largeur + hauteur) + (cadreRenfort ? largeur : 0);
        surfaceVerre = largeur * hauteur;
        cuts = cadreRenfort ? 5 : 4;
        break;
      case 'box':
        // Box simple: cadre avant + arriere + profondeur laterale
        baseMetres = 2 * (largeur + hauteur) + 2 * profondeur;
        surfaceVerre = largeur * hauteur;
        cuts = 6;
        break;
      default:
        baseMetres = 0;
        surfaceVerre = 0;
        cuts = 0;
    }

    const pertesCoupeM = Math.max(0, this.toNumber(raw.options?.pertesCoupeCm)) / 100;
    const margeChuteRate = Math.max(0, this.toNumber(raw.options?.margeChute)) / 100;

    const pertesTotales = cuts * pertesCoupeM;
    const consommationTotaleMetres = (baseMetres + pertesTotales) * (1 + margeChuteRate);

    const nbBarres = longueurBarre > 0 && consommationTotaleMetres > 0
      ? Math.ceil(consommationTotaleMetres / longueurBarre)
      : 0;
    const longueurAcheteeTotale = nbBarres * longueurBarre;
    const chuteTotale = nbBarres > 0
      ? Math.max(0, longueurAcheteeTotale - consommationTotaleMetres)
      : 0;

    const coutBarres = nbBarres * prixBarre;

    const activerVerre = !!raw.verre?.activerVerre;
    const prixVerreM2 = Math.max(0, this.toNumber(raw.verre?.prixVerreM2));
    const coutVerre = activerVerre ? surfaceVerre * prixVerreM2 : 0;

    const accessoires = (raw.accessoires ?? []) as AccessoryFormValue[];
    const coutAccessoires = accessoires.reduce((sum, acc) => {
      const quantite = Math.max(0, this.toNumber(acc.quantite));
      const prixUnitaire = Math.max(0, this.toNumber(acc.prixUnitaire));
      return sum + quantite * prixUnitaire;
    }, 0);

    const coutTotal = coutBarres + coutVerre + coutAccessoires;

    this.result = {
      baseMetres,
      consommationTotaleMetres,
      longueurAcheteeTotale,
      nbBarres,
      chuteTotale,
      coutBarres,
      surfaceVerre,
      coutVerre,
      coutAccessoires,
      coutTotal
    };
  }

  private createAccessory(): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      designation: [''],
      quantite: [1, [Validators.min(0)]],
      prixUnitaire: [0, [Validators.min(0)]]
    });
  }

  private toNumber(value: unknown): number {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }
}
<section class="panel">
  <div class="panel-header">
    <div>
      <h1>Estimation de prix</h1>
      <p>Calculez la consommation de profil&eacute;s et le co&ucirc;t total en temps r&eacute;el.</p>
    </div>
    <div class="panel-actions no-print">
      <button class="btn ghost" type="button" (click)="reset()">R&eacute;initialiser</button>
      <button class="btn primary" type="button" (click)="print()">Imprimer estimation</button>
    </div>
  </div>

  <form class="estimation-grid" [formGroup]="form">
    <section class="card">
      <h2>Param&egrave;tres barres</h2>
      <div class="grid-2" formGroupName="barre">
        <label class="field">
          <span>Longueur barre (m)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="longueurBarre">
        </label>
        <label class="field">
          <span>Prix barre (DT)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="prixBarre">
        </label>
      </div>
    </section>

    <section class="card">
      <h2>Produit &agrave; fabriquer</h2>
      <div class="grid-2" formGroupName="produit">
        <label class="field">
          <span>Type</span>
          <select class="input" formControlName="type">
            <option value="carre">Carr&eacute;</option>
            <option value="rectangle">Rectangle</option>
            <option value="porte">Porte</option>
            <option value="box">Box</option>
          </select>
        </label>

        <label class="field" *ngIf="productType === 'carre'">
          <span>C&ocirc;t&eacute; (m)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="cote">
        </label>

        <label class="field" *ngIf="productType !== 'carre'">
          <span>Largeur (m)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="largeur">
        </label>

        <label class="field" *ngIf="productType !== 'carre'">
          <span>Hauteur (m)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="hauteur">
        </label>

        <label class="field" *ngIf="productType === 'box'">
          <span>Profondeur (m)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="profondeur">
        </label>

        <label class="field checkbox" *ngIf="productType === 'porte'">
          <input type="checkbox" formControlName="cadreRenfort">
          <span>Ajouter renfort (traverse)</span>
        </label>
      </div>
    </section>

    <section class="card">
      <h2>Options de coupe</h2>
      <div class="grid-2" formGroupName="options">
        <label class="field">
          <span>Marge chute (%)</span>
          <input class="input" type="number" min="0" step="0.1" formControlName="margeChute">
        </label>
        <label class="field">
          <span>Pertes par coupe (cm)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="pertesCoupeCm">
        </label>
      </div>
    </section>

    <section class="card">
      <h2>Verre</h2>
      <div class="grid-2" formGroupName="verre">
        <label class="field checkbox">
          <input type="checkbox" formControlName="activerVerre">
          <span>Inclure le vitrage</span>
        </label>
        <label class="field">
          <span>Prix verre (DT/m&sup2;)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="prixVerreM2">
        </label>
      </div>
      <div class="hint" *ngIf="result.surfaceVerre > 0">
        Surface verre estim&eacute;e : <strong>{{ result.surfaceVerre | number:'1.2-2' }} m&sup2;</strong>
      </div>
    </section>

    <section class="card">
      <div class="section-head">
        <h2>Accessoires</h2>
        <button class="btn outline" type="button" (click)="addAccessory()">Ajouter accessoire</button>
      </div>

      <div class="accessories" formArrayName="accessoires">
        <div class="accessory-row accessory-head">
          <div>D&eacute;signation</div>
          <div>Qt&eacute;</div>
          <div>PU (DT)</div>
          <div></div>
        </div>

        <div
          class="accessory-row"
          *ngFor="let acc of accessoires.controls; let i = index"
          [formGroupName]="i"
        >
          <input class="input" formControlName="designation" placeholder="Poign&eacute;e, visserie...">
          <input class="input" type="number" min="0" step="1" formControlName="quantite">
          <input class="input" type="number" min="0" step="0.01" formControlName="prixUnitaire">
          <button class="btn danger" type="button" (click)="removeAccessory(i)">Supprimer</button>
        </div>

        <div class="empty" *ngIf="accessoires.length === 0">
          Aucun accessoire ajout&eacute;.
        </div>
      </div>
    </section>

    <section class="card results">
      <h2>R&eacute;sultats</h2>
      <div class="results-grid">
        <div>
          <span>Longueur totale consomm&eacute;e</span>
          <strong>{{ result.consommationTotaleMetres | number:'1.2-2' }} m</strong>
        </div>
        <div>
          <span>Nombre de barres</span>
          <strong>{{ result.nbBarres }}</strong>
        </div>
        <div>
          <span>Longueur achet&eacute;e totale</span>
          <strong>{{ result.longueurAcheteeTotale | number:'1.2-2' }} m</strong>
        </div>
        <div>
          <span>Chute totale</span>
          <strong>{{ result.chuteTotale | number:'1.2-2' }} m</strong>
        </div>
        <div>
          <span>Co&ucirc;t barres</span>
          <strong>{{ result.coutBarres | number:'1.2-2' }} DT</strong>
        </div>
        <div>
          <span>Co&ucirc;t verre</span>
          <strong>{{ result.coutVerre | number:'1.2-2' }} DT</strong>
        </div>
        <div>
          <span>Co&ucirc;t accessoires</span>
          <strong>{{ result.coutAccessoires | number:'1.2-2' }} DT</strong>
        </div>
        <div class="grand-total">
          <span>Co&ucirc;t total</span>
          <strong>{{ result.coutTotal | number:'1.2-2' }} DT</strong>
        </div>
      </div>
    </section>
  </form>
</section>
